// ─────────────────────────────────────────────
// Active Spam Tracker — used by stopspam
// ─────────────────────────────────────────────

var (
	activeSpamChats   = make(map[int64]bool)
	activeSpamChatsMu sync.Mutex
)

func setSpamActive(chatID int64) {
	activeSpamChatsMu.Lock()
	activeSpamChats[chatID] = true
	activeSpamChatsMu.Unlock()
}

func setSpamStopped(chatID int64) {
	activeSpamChatsMu.Lock()
	delete(activeSpamChats, chatID)
	activeSpamChatsMu.Unlock()
}

func isSpamActive(chatID int64) bool {
	activeSpamChatsMu.Lock()
	defer activeSpamChatsMu.Unlock()
	return activeSpamChats[chatID]
}

// ─────────────────────────────────────────────
// .spam
// ─────────────────────────────────────────────

func spamHandler(m *telegram.NewMessage) error {
	args := GetArgs(m)
	parts := strings.SplitN(args, " ", 2)
	if len(parts) < 2 {
		Reply(m, "⚠️ <b>ᴜsᴀɢᴇ:</b>\n<code>.spam 10 Hello World</code>")
		return nil
	}
	var count int
	fmt.Sscanf(parts[0], "%d", &count)
	if count < 1 {
		Reply(m, "❌ ᴄᴏᴜɴᴛ ᴍᴜsᴛ ʙᴇ ᴀᴛ ʟᴇᴀsᴛ 1.")
		return nil
	}
	text := parts[1]

	// Capture replyToID once, before the loop
	var replyToID int32
	if m.IsReply() {
		replyMsg, err := m.GetReplyMessage()
		if err == nil && replyMsg != nil {
			replyToID = int32(replyMsg.ID)
		}
	}

	_, _ = m.Delete()
	setSpamActive(m.ChatID())
	defer setSpamStopped(m.ChatID())

	for i := 0; i < count; i++ {
		if !isSpamActive(m.ChatID()) {
			break
		}
		opts := &telegram.SendOptions{ParseMode: telegram.HTML}
		if replyToID > 0 {
			opts.ReplyID = replyToID
		}
		_, err := m.Client.SendMessage(m.ChatID(), text, opts)
		if err != nil {
			if strings.Contains(strings.ToUpper(err.Error()), "FLOOD_WAIT") {
				var wait int
				fmt.Sscanf(err.Error(), "FLOOD_WAIT_%d", &wait)
				if wait <= 0 {
					wait = 5
				}
				time.Sleep(time.Duration(wait+1) * time.Second)
				i--
				continue
			}
			time.Sleep(2 * time.Second)
			continue
		}
		time.Sleep(700 * time.Millisecond)
	}
	return nil
}

// ─────────────────────────────────────────────
// .ds / .delayspam
// ─────────────────────────────────────────────

func delaySpamHandler(m *telegram.NewMessage) error {
	args := GetArgs(m)
	parts := strings.SplitN(args, " ", 3)
	if len(parts) < 3 {
		Reply(m, "⚠️ <b>ᴜsᴀɢᴇ:</b>\n<code>.ds 1 10 Hello</code>")
		return nil
	}
	var delaySec float64
	var count int
	fmt.Sscanf(parts[0], "%f", &delaySec)
	fmt.Sscanf(parts[1], "%d", &count)
	if count < 1 {
		Reply(m, "❌ ᴄᴏᴜɴᴛ ᴍᴜsᴛ ʙᴇ ᴀᴛ ʟᴇᴀsᴛ 1.")
		return nil
	}
	text := parts[2]
	delay := time.Duration(delaySec * float64(time.Second))

	// Capture replyToID once, before the loop
	var replyToID int32
	if m.IsReply() {
		replyMsg, err := m.GetReplyMessage()
		if err == nil && replyMsg != nil {
			replyToID = int32(replyMsg.ID)
		}
	}

	_, _ = m.Delete()
	setSpamActive(m.ChatID())
	defer setSpamStopped(m.ChatID())

	for i := 0; i < count; i++ {
		if !isSpamActive(m.ChatID()) {
			break
		}
		opts := &telegram.SendOptions{ParseMode: telegram.HTML}
		if replyToID > 0 {
			opts.ReplyID = replyToID
		}
		_, err := m.Client.SendMessage(m.ChatID(), text, opts)
		if err != nil {
			if strings.Contains(strings.ToUpper(err.Error()), "FLOOD_WAIT") {
				var wait int
				fmt.Sscanf(err.Error(), "FLOOD_WAIT_%d", &wait)
				if wait <= 0 {
					wait = 5
				}
				time.Sleep(time.Duration(wait+1) * time.Second)
				i--
				continue
			}
			time.Sleep(2 * time.Second)
			continue
		}
		time.Sleep(delay)
	}
	return nil
}

// ─────────────────────────────────────────────
// .sspam
// ─────────────────────────────────────────────

func sspamHandler(m *telegram.NewMessage) error {
	if !m.IsReply() {
		Reply(m, "↩️ ʀᴇᴘʟʏ ᴛᴏ ᴍᴇᴅɪᴀ / sᴛɪᴄᴋᴇʀ ᴡɪᴛʜ:\n<code>.sspam 10</code>")
		return nil
	}
	var count int
	fmt.Sscanf(GetArgs(m), "%d", &count)
	if count < 1 {
		Reply(m, "❌ ᴄᴏᴜɴᴛ ᴍᴜsᴛ ʙᴇ ᴀᴛ ʟᴇᴀsᴛ 1.")
		return nil
	}
	replyMsg, err := m.GetReplyMessage()
	if err != nil {
		Reply(m, "❌ ꜰᴀɪʟᴇᴅ ᴛᴏ ɢᴇᴛ ʀᴇᴘʟɪᴇᴅ ᴍᴇssᴀɢᴇ.")
		return nil
	}
	if replyMsg.Media() == nil {
		Reply(m, "❌ ʀᴇᴘʟɪᴇᴅ ᴍᴇssᴀɢᴇ ʜᴀs ɴᴏ ᴍᴇᴅɪᴀ.")
		return nil
	}

	_, _ = m.Delete()
	setSpamActive(m.ChatID())
	defer setSpamStopped(m.ChatID())

	for i := 0; i < count; i++ {
		if !isSpamActive(m.ChatID()) {
			break
		}
		_, err := m.Client.SendMedia(m.ChatID(), replyMsg.Media(), nil)
		if err != nil {
			if strings.Contains(strings.ToUpper(err.Error()), "FLOOD_WAIT") {
				var wait int
				fmt.Sscanf(err.Error(), "FLOOD_WAIT_%d", &wait)
				if wait <= 0 {
					wait = 8
				}
				time.Sleep(time.Duration(wait+1) * time.Second)
				i--
				continue
			}
			time.Sleep(3 * time.Second)
			continue
		}
		time.Sleep(1500 * time.Millisecond)
	}
	return nil
}

